package com.github.namuan.fintech.reconciliation;
import java.util.*;
public final class ReconciliationJob { private final MatchRule rule; public ReconciliationJob(MatchRule rule){this.rule=rule;} public List<ReconciliationBreak> compare(ReconciliationSource left, ReconciliationSource right){ var breaks = new ArrayList<ReconciliationBreak>(); var rightRecords = new ArrayList<>(right.records()); for (var l: left.records()){ var match = rightRecords.stream().filter(r -> rule.matches(l,r)).findFirst(); if(match.isPresent()) rightRecords.remove(match.get()); else breaks.add(new ReconciliationBreak(UUID.randomUUID().toString(), l, "missing or different on right")); } for (var r: rightRecords) breaks.add(new ReconciliationBreak(UUID.randomUUID().toString(), r, "extra on right")); return breaks; } }
